LOGICPULSE.Mouse.initialize();


//=============================================================================
// LPInventoryProvider.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

//=============================================================================
// Inventory Provider
//=============================================================================

LOGICPULSE.InventoryProvider = {

    _entries: {},

    _dirty: true,

    //--------------------------------
    // Refresh Cache
    //--------------------------------

    refresh() {

        const Category = LOGICPULSE.Constants.Category;

        this._entries = {};

        for (const category of Object.values(Category)) {

            this._entries[category] = [];

        }

        this.buildInventory();

        this.sortEntries();

        this._dirty = false;

    },

    //--------------------------------
    // Mark Dirty
    //--------------------------------

    markDirty() {

        this._dirty = true;

    },

    //--------------------------------
    // Ensure Ready
    //--------------------------------

    ensureReady() {

        if (this._dirty) {

            this.refresh();

        }

    },

    //--------------------------------
    // Build Inventory
    //--------------------------------

    buildInventory() {

        this.buildItems();
        this.buildWeapons();
        this.buildArmors();

    },

    //--------------------------------
    // Build Items
    //--------------------------------

    buildItems() {

        const items = $gameParty.items();

        for (const item of items) {

            const entry = this.buildEntry(item);

            this._entries[entry.category].push(entry);

        }

    },

    //--------------------------------
    // Build Weapons
    //--------------------------------

    buildWeapons() {

        const weapons = $gameParty.weapons();

        const Category = LOGICPULSE.Constants.Category;

        for (const weapon of weapons) {

            const entry = this.buildEntry(

                weapon,
                Category.Weapon

            );

            this._entries[Category.Weapon].push(entry);

        }

    },

    //--------------------------------
    // Build Armors
    //--------------------------------

    buildArmors() {

        const armors = $gameParty.armors();

        const Category = LOGICPULSE.Constants.Category;

        for (const armor of armors) {

            const entry = this.buildEntry(

                armor,
                Category.Armor

            );

            this._entries[Category.Armor].push(entry);

        }

    },

    //--------------------------------
    // Build Entry
    //--------------------------------

    buildEntry(item, category = null) {

        return {

            id: item.id,

            item: item,

            amount: $gameParty.numItems(item),

            rarity: this.getRarity(item),

            category: category || this.getCategory(item)

        };

    },

    //--------------------------------
    // Get Items
    //--------------------------------

    getItems(category) {

        this.ensureReady();

        return this._entries[category] || [];

    },

    //--------------------------------
    // Consumables
    //--------------------------------

    getConsumables() {

        return this.getItems(

            LOGICPULSE.Constants.Category.Consumable

        );

    },

    //--------------------------------
    // Materials
    //--------------------------------

    getMaterials() {

        return this.getItems(

            LOGICPULSE.Constants.Category.Material

        );

    },

    //--------------------------------
    // Key Items
    //--------------------------------

    getKeyItems() {

        return this.getItems(

            LOGICPULSE.Constants.Category.Key

        );

    },

    //--------------------------------
    // Hidden B
    //--------------------------------

    getHiddenItemsB() {

        return this.getItems(

            LOGICPULSE.Constants.Category.HiddenB

        );

    },

    //--------------------------------
    // Weapons
    //--------------------------------

    getWeapons() {

        return this.getItems(

            LOGICPULSE.Constants.Category.Weapon

        );

    },

    //--------------------------------
    // Armors
    //--------------------------------

    getArmors() {

        return this.getItems(

            LOGICPULSE.Constants.Category.Armor

        );

    },

    //--------------------------------
    // Has Items
    //--------------------------------

    hasItems(category) {

        return this.getItems(category).length > 0;

    },


    //--------------------------------
    // Has Category Content
    //--------------------------------

    hasCategoryContent(category) {

        switch (category) {

            case LOGICPULSE.Constants.Category.Consumable:
            case LOGICPULSE.Constants.Category.Material:
            case LOGICPULSE.Constants.Category.Key:
            case LOGICPULSE.Constants.Category.HiddenB:
            case LOGICPULSE.Constants.Category.Weapon:
            case LOGICPULSE.Constants.Category.Armor:

                return this.hasItems(category);

            case "synthesizer":

                return this.getSynthesizerItems().length > 0;

            default:

                return false;

        }

    },



    //--------------------------------
    // Count
    //--------------------------------

    count(category) {

        return this.getItems(category).length;

    },

    //--------------------------------
    // Get All
    //--------------------------------

    getAll() {

        this.ensureReady();

        return Object.values(this._entries).flat();

    },

    //--------------------------------
    // Synthesizer Items
    //--------------------------------

    getSynthesizerItems() {

        const entries = [];

        for (const item of $dataItems) {

            if (!item) {

                continue;

            }

            if (

                !LOGICPULSE.RecipeManager.hasRecipe(

                    item

                )

            ) {

                continue;

            }

            entries.push(

                this.buildEntry(item)

            );

        }

        entries.sort((a, b) => {

            const aCraftable = LOGICPULSE.RecipeManager.canCraft(a.item);
            const bCraftable = LOGICPULSE.RecipeManager.canCraft(b.item);

            // Craftable items first
            if (aCraftable !== bCraftable) {

                return bCraftable - aCraftable;

            }

            // Higher rarity first
            if (a.rarity !== b.rarity) {

                return b.rarity - a.rarity;

            }

            // Alphabetical
            return a.item.name.localeCompare(

                b.item.name

            );

        });

        return entries;

    },


    //--------------------------------
    // Craftable Items
    //--------------------------------

    getCraftableItems() {

        return this.getSynthesizerItems();

    },

    //--------------------------------
    // Can Craft Entry
    //--------------------------------

    canCraftEntry(entry) {

        if (!entry) {

            return false;

        }

        return LOGICPULSE.RecipeManager.canCraft(

            entry.item

        );

    },


    //--------------------------------
    // Category
    //--------------------------------

    getCategory(item) {

        const Category = LOGICPULSE.Constants.Category;

        switch (item.itypeId) {

            case 1:
                return Category.Consumable;

            case 2:
                return Category.Key;

            case 3:
                return Category.Material;

            case 4:
                return Category.HiddenB;

            default:
                return Category.Unknown;

        }

    },


    //--------------------------------
    // Rarity
    //--------------------------------

    getRarity(item) {

        return Number(item.meta.rarity || 1);

    },


    //--------------------------------
    // Selected Amount
    //--------------------------------

    amount(item) {

        if (!item) {

            return 0;

        }

        return $gameParty.numItems(item);

    },


    //--------------------------------
    // Sort Entries
    //--------------------------------

    sortEntries() {

        for (const category of Object.keys(this._entries)) {

            this._entries[category].sort((a, b) => {

                // Higher rarity first
                if (a.rarity !== b.rarity) {

                    return b.rarity - a.rarity;

                }

                // Then alphabetical
                return a.item.name.localeCompare(

                    b.item.name

                );

            });

        }

    },

    //--------------------------------
    // Can Use
    //--------------------------------

    canUse(item) {

        if (!item) {

            return false;

        }

        return $gameParty.canUse(item);

    },

    //--------------------------------
    // Show Use Button
    //--------------------------------

    showUseButton(item) {

        if (!item) {

            return false;

        }

        // Weapons / Armors
        if (DataManager.isWeapon(item)) {

            return false;

        }

        if (DataManager.isArmor(item)) {

            return false;

        }

        // Only normal items
        if (!DataManager.isItem(item)) {

            return false;

        }

        // Only regular consumable items
        if (item.itypeId !== 1) {

            return false;

        }

        // Database:
        // 0 = Always
        // 1 = Battle
        // 2 = Menu
        // 3 = Never

        return item.occasion !== 3;

    },

    //--------------------------------
    // Use Item
    //--------------------------------

    useItem(item) {

        if (!this.canUse(item)) {

            return false;

        }

        const actor = $gameParty.leader();

        if (!actor) {

            return false;

        }

        const action = new Game_Action(actor);

        action.setItemObject(item);

        action.apply(actor);

        $gameParty.consumeItem(item);

        this.markDirty();

        return true;

    },

    //--------------------------------
    // Gain Item
    //--------------------------------

    gainItem(item, amount) {

        if (!item || amount <= 0) {

            return;

        }

        $gameParty.gainItem(

            item,

            amount,

            false

        );

        this.markDirty();

    },

    //--------------------------------
    // Lose Item
    //--------------------------------

    loseItem(item, amount) {

        if (!item || amount <= 0) {

            return;

        }

        $gameParty.loseItem(

            item,

            amount,

            false

        );

        this.markDirty();

    },

};


//=============================================================================
// LPInventoryController.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

//=============================================================================
// Inventory Controller
//=============================================================================

LOGICPULSE.InventoryController = class {

    //--------------------------------
    // Initialize
    //--------------------------------

    constructor(scene) {

        this._scene = scene;

    }

    //--------------------------------
    // Update
    //--------------------------------

    update() {

        this.updateGridInput();
        this.updateCategoryInput();
        this.updateConfirmInput();
        this.updateCancelInput();

    }

    //--------------------------------
    // Grid Input
    //--------------------------------

    updateGridInput() {

        const grid = this.grid();

        if (!grid) {

            return;

        }

        const B = LOGICPULSE.Bindings;

        let moved = false;

        if (LOGICPULSE.Input.isRepeated(B.MoveLeft)) {

            grid.moveLeft();
            moved = true;

        }

        else if (LOGICPULSE.Input.isRepeated(B.MoveRight)) {

            grid.moveRight();
            moved = true;

        }

        else if (LOGICPULSE.Input.isRepeated(B.MoveUp)) {

            grid.moveUp();
            moved = true;

        }

        else if (LOGICPULSE.Input.isRepeated(B.MoveDown)) {

            grid.moveDown();
            moved = true;

        }

        if (moved) {

            this.onSelectionChanged();

        }

    }

    //--------------------------------
    // Category Input
    //--------------------------------

    updateCategoryInput() {

        const B = LOGICPULSE.Bindings;

        if (LOGICPULSE.Input.isTriggered(B.NextCategory)) {

            this.nextCategory();

        }

        else if (LOGICPULSE.Input.isTriggered(B.PreviousCategory)) {

            this.previousCategory();

        }

    }

    //--------------------------------
    // Confirm Input
    //--------------------------------

    updateConfirmInput() {

        if (

            LOGICPULSE.Input.isTriggered(

                LOGICPULSE.Bindings.Confirm

            )

        ) {

            this.onConfirm();

        }

    }

    //--------------------------------
    // Cancel Input
    //--------------------------------

    updateCancelInput() {

        if (

            LOGICPULSE.Input.isTriggered(

                LOGICPULSE.Bindings.Cancel

            )

        ) {

            this.onCancel();

        }

    }

    //--------------------------------
    // Next Category
    //--------------------------------

    nextCategory() {

        this.changeCategory(1);

    }

    //--------------------------------
    // Previous Category
    //--------------------------------

    previousCategory() {

        this.changeCategory(-1);

    }

    //--------------------------------
    // Change Category
    //--------------------------------

    changeCategory(direction) {

        const sidebar = this.sidebar();

        if (!sidebar) {

            return;

        }

        const count = sidebar.categoryCount();

        let index = sidebar.selectedIndex();

        for (let i = 0; i < count; i++) {

            index += direction;

            if (index < 0) {

                index = count - 1;

            }

            else if (index >= count) {

                index = 0;

            }

            const definition = sidebar.definition(index);

            if (this.isCategoryAvailable(definition.category)) {

                sidebar.select(index);


                //--------------------------------
                // Open Synthesizer Scene
                //--------------------------------

                if (definition.category === "synthesizer") {
                    // Directly switch without pushing/poping
                    SceneManager.goto(LOGICPULSE.Scenes.Synthesizer);
                    return;
                }


                //--------------------------------
                // Normal Inventory Categories
                //--------------------------------

                this.grid().setCategory(

                    definition.category

                );


                if (sidebar.refreshVisuals) {

                    sidebar.refreshVisuals();

                }


                this.onSelectionChanged();

                return;

            }

        }

    }

    //--------------------------------
    // Category Available
    //--------------------------------

    isCategoryAvailable(category) {

        return LOGICPULSE.InventoryProvider.hasCategoryContent(

            category

        );

    }

    //--------------------------------
    // Selection Changed
    //--------------------------------

    onSelectionChanged() {

        if (this._scene.onSelectionChanged) {

            this._scene.onSelectionChanged();

        }

    }

    //--------------------------------
    // Confirm
    //--------------------------------

    onConfirm() {

        if (this._scene.onConfirm) {

            this._scene.onConfirm();

        }

    }

    //--------------------------------
    // Cancel
    //--------------------------------

    onCancel() {

        if (this._scene.onCancel) {

            this._scene.onCancel();

        }

    }

    //--------------------------------
    // Scene
    //--------------------------------

    scene() {

        return this._scene;

    }

    //--------------------------------
    // Grid
    //--------------------------------

    grid() {

        return this.scene()._grid;

    }

    //--------------------------------
    // Sidebar
    //--------------------------------

    sidebar() {

        return this.scene()._sidebar;

    }

    //--------------------------------
    // Showcase
    //--------------------------------

    showcase() {

        return this.scene()._showcase;

    }

};


//=============================================================================
// LPSynthesizerController.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

//=============================================================================
// Synthesizer Controller
//=============================================================================

LOGICPULSE.SynthesizerController = class {

    //--------------------------------
    // Initialize
    //--------------------------------

    constructor(scene) {
        this._scene = scene;
        this._state = "select";
        this._craftingItem = null;
    }

    //--------------------------------
    // Update
    //--------------------------------

    update() {
        if (this._state === "select") {
            this.updateGridInput();
        } else {
            this.updateQuantityInput();
        }

        this.updateConfirmInput();
        this.updateCancelInput();
        this.updateCategoryInput();
    }

    //--------------------------------
    // Grid Input (keyboard)
    //--------------------------------

    updateGridInput() {
        const grid = this.grid();
        if (!grid) return;

        const B = LOGICPULSE.Bindings;
        let moved = false;

        if (LOGICPULSE.Input.isRepeated(B.MoveLeft)) {
            grid.moveLeft();
            moved = true;
        } else if (LOGICPULSE.Input.isRepeated(B.MoveRight)) {
            grid.moveRight();
            moved = true;
        } else if (LOGICPULSE.Input.isRepeated(B.MoveUp)) {
            grid.moveUp();
            moved = true;
        } else if (LOGICPULSE.Input.isRepeated(B.MoveDown)) {
            grid.moveDown();
            moved = true;
        }

        if (moved) {
            this.onSelectionChanged();
        }
    }

    //--------------------------------
    // Quantity Input (keyboard)
    //--------------------------------

    updateQuantityInput() {
        const controller = this.quantityController();
        if (!controller) return;

        let step = 1;
        if (Input.isPressed("skip")) step = 10;
        if (Input.isPressed("shift")) step = controller.max();

        const B = LOGICPULSE.Bindings;

        if (LOGICPULSE.Input.isRepeated(B.MoveLeft)) {
            controller.decrease(step);
        } else if (LOGICPULSE.Input.isRepeated(B.MoveRight)) {
            controller.increase(step);
        }
    }

    //--------------------------------
    // Category Input
    //--------------------------------

    updateCategoryInput() {
        const B = LOGICPULSE.Bindings;
        if (
            LOGICPULSE.Input.isTriggered(B.NextCategory) ||
            LOGICPULSE.Input.isTriggered(B.PreviousCategory)
        ) {
            SceneManager.goto(LOGICPULSE.Scenes.Inventory);
        }
    }

    //--------------------------------
    // Confirm Input (Enter key + mouse double-click)
    //--------------------------------

    updateConfirmInput() {
        if (LOGICPULSE.Input.isTriggered(LOGICPULSE.Bindings.Confirm)) {
            this.onConfirm();
        }
    }

    //--------------------------------
    // Cancel Input
    //--------------------------------

    updateCancelInput() {
        if (LOGICPULSE.Input.isTriggered(LOGICPULSE.Bindings.Cancel)) {
            if (this._state === "craft") {
                this.leaveCraftMode();
            } else {
                this.onCancel();
            }
        }
    }

    //=========================================================================
    // CONFIRM / CRAFT LOGIC
    //=========================================================================

    //--------------------------------
    // Confirm (Enter key or double-click)
    //--------------------------------

    onConfirm() {
        if (this._state === "select") {
            this.enterCraftMode();
        } else if (this._state === "craft") {
            this.craft(); // Enter key crafts when in craft mode
        }
    }

    //--------------------------------
    // Enter Craft Mode
    //--------------------------------

    enterCraftMode() {
        const entry = this.grid().selectedEntry();
        if (!entry) return;

        if (!LOGICPULSE.RecipeManager.canCraft(entry.item)) {
            return;
        }

        this._state = "craft";
        this._craftingItem = entry.item;
        this.scene()._quantityController?.setItem(entry.item);
        this.scene().enterCraftMode?.(entry.item);
    }

    //--------------------------------
    // Leave Craft Mode
    //--------------------------------

    leaveCraftMode() {
        this._state = "select";
        this._craftingItem = null;
        this.scene().leaveCraftMode?.();
        this.scene()._quantityController?.setItem(null);
    }

    //--------------------------------
    // Craft (called by Enter key or craft button)
    //--------------------------------

    craft() {
        if (this._state !== "craft") return;
        this.scene().craftCurrentItem?.();

        // After crafting, refresh the quantity controller
        const entry = this.grid().selectedEntry();
        if (entry) {
            this.scene()._quantityController?.setItem(entry.item);
        }
        this.onSelectionChanged();
    }

    //=========================================================================
    // SELECTION CHANGED
    //=========================================================================

    onSelectionChanged() {
        const entry = this.grid().selectedEntry();

        if (this._state === "craft" && entry) {
            if (entry.item !== this._craftingItem) {
                this.leaveCraftMode();
                this._updateUI(entry);
                return;
            }
            return;
        }

        this._updateUI(entry);
    }

    _updateUI(entry) {
        if (!entry) {
            this.scene()._recipePanel?.clear();
            this.scene()._showcase?.setItem?.(null);
            this.scene()._quantityController?.setItem?.(null);
            this.scene()._craftButton?.setItem?.(null);
            this.scene().onSelectionChanged?.();
            return;
        }

        const recipe = LOGICPULSE.RecipeManager.recipe(entry.item);

        this.scene()._recipePanel?.setRecipe(recipe);
        this.scene()._showcase?.setItem?.(entry.item);
        this.scene()._quantityController?.setItem?.(entry.item);
        this.scene()._craftButton?.setItem?.(entry.item);
        this.scene().onSelectionChanged?.();
    }

    //=========================================================================
    // HELPERS
    //=========================================================================

    onCancel() {
        this.scene().onCancel?.();
    }

    scene() { return this._scene; }
    grid() { return this.scene()._craftGrid; }
    sidebar() { return this.scene()._sidebar; }
    quantityController() { return this.scene()._quantityController; }
};


