//=============================================================================
// LPRecipeManager.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

//=============================================================================
// Recipe Manager
//=============================================================================

LOGICPULSE.RecipeManager = {

    //--------------------------------
    // Initialize
    //--------------------------------

    initialize() {

        this._recipes = {};

        this.buildCache();

    },

    //--------------------------------
    // Build Cache
    //--------------------------------

    buildCache() {

        this._recipes = {};

        if (!$dataItems) {

            return;

        }

        for (const item of $dataItems) {

            if (!item) {

                continue;

            }

            const recipe = this.parseRecipe(item.note);

            if (recipe.length > 0) {

                this._recipes[item.id] = recipe;

            }

        }

    },

    //--------------------------------
    // Parse Recipe
    //--------------------------------

    parseRecipe(note) {

        if (!note) {

            return [];

        }

        const match = note.match(

            /<Recipe>([\s\S]*?)<\/Recipe>/i

        );

        if (!match) {

            return [];

        }

        const result = [];

        const lines =

            match[1]

                .split(/\r?\n/)

                .map(line => line.trim())

                .filter(line => line.length > 0);

        for (const line of lines) {

            const parts = line.split(":");

            if (parts.length !== 2) {

                continue;

            }

            const itemId = Number(parts[0]);

            const amount = Number(parts[1]);

            if (

                Number.isNaN(itemId) ||

                Number.isNaN(amount)

            ) {

                continue;

            }

            result.push({

                itemId: itemId,

                amount: amount

            });

        }

        return result;

    },

    //--------------------------------
    // Has Recipe
    //--------------------------------

    hasRecipe(item) {

        if (!item) {

            return false;

        }

        return !!this._recipes[item.id];

    },


    //--------------------------------
    // Recipe
    //--------------------------------

    recipe(item) {

        if (!item) {

            return [];

        }

        return this._recipes[item.id] || [];

    },

    //--------------------------------
    // Get Recipe
    //--------------------------------

    getRecipe(item) {

        return this.recipe(item);

    },

    //--------------------------------
    // Ingredient Items
    //--------------------------------

    ingredientItems(item) {

        return this.recipe(item).map(entry => ({

            item: $dataItems[entry.itemId],

            amount: entry.amount

        }));

    },

    //--------------------------------
    // Can Craft
    //--------------------------------

    canCraft(item) {

        if (!this.hasRecipe(item)) {

            return false;

        }

        return this.maxCraftAmount(item) > 0;

    },

    //--------------------------------
    // Max Craft Amount
    //--------------------------------

    maxCraftAmount(item) {

        const recipe = this.recipe(item);

        if (recipe.length === 0) {

            return 0;

        }

        let max = Infinity;

        for (const ingredient of recipe) {

            const material =

                $dataItems[ingredient.itemId];

            if (!material) {

                return 0;

            }

            const owned =

                LOGICPULSE.InventoryProvider.amount(

                    material

                );

            const craftable = Math.floor(

                owned / ingredient.amount

            );

            max = Math.min(

                max,

                craftable

            );

        }

        return Math.max(

            0,

            max

        );

    },

    //--------------------------------
    // Missing Ingredients
    //--------------------------------

    missingIngredients(item) {

        const missing = [];

        for (const ingredient of this.recipe(item)) {

            const material =

                $dataItems[ingredient.itemId];

            if (!material) {

                continue;

            }

            const owned =

                LOGICPULSE.InventoryProvider.amount(

                    material

                );

            if (owned < ingredient.amount) {

                missing.push({

                    item: material,

                    required: ingredient.amount,

                    owned: owned

                });

            }

        }

        return missing;

    }

};

//=============================================================================
// Database Hook
//=============================================================================

(() => {

    const alias = DataManager.isDatabaseLoaded;

    DataManager.isDatabaseLoaded = function() {

        if (!alias.call(this)) {

            return false;

        }

        if (!LOGICPULSE.RecipeManager._recipes) {

            LOGICPULSE.RecipeManager.initialize();

        }

        return true;

    };

})();


//=============================================================================
// LPCraftManager.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

//=============================================================================
// Craft Manager
//=============================================================================

LOGICPULSE.CraftManager = {

    //--------------------------------
    // Can Craft
    //--------------------------------

    canCraft(item, amount = 1) {

        if (!item) {

            return false;

        }

        if (!LOGICPULSE.RecipeManager.hasRecipe(item)) {

            return false;

        }

        return (

            LOGICPULSE.RecipeManager.maxCraftAmount(item)

            >=

            amount

        );

    },

    //--------------------------------
    // Craft
    //--------------------------------

    craft(item, amount = 1) {

        if (

            !this.canCraft(

                item,

                amount

            )

        ) {

            return false;

        }

        const recipe =

            LOGICPULSE.RecipeManager.recipe(

                item

            );

        //--------------------------------
        // Remove Materials
        //--------------------------------

        for (const ingredient of recipe) {

            const material =

                $dataItems[

                    ingredient.itemId

                    ];

            LOGICPULSE.InventoryProvider.loseItem(

                material,

                ingredient.amount * amount

            );

        }

        //--------------------------------
        // Give Crafted Item
        //--------------------------------

        LOGICPULSE.InventoryProvider.gainItem(

            item,

            amount

        );


        return true;

    },

    //--------------------------------
    // Max Craft Amount
    //--------------------------------

    maxCraftAmount(item) {

        return LOGICPULSE.RecipeManager.maxCraftAmount(

            item

        );

    },

    //--------------------------------
    // Recipe
    //--------------------------------

    recipe(item) {

        return LOGICPULSE.RecipeManager.recipe(

            item

        );

    }

};


//=============================================================================
// LPAnimator.js
//=============================================================================

window.LOGICPULSE = window.LOGICPULSE || {};

//=============================================================================
// Animator
//=============================================================================

LOGICPULSE.Animator = {

    _animations: [],

    //--------------------------------
    // Update
    //--------------------------------

    update() {

        for (let i = this._animations.length - 1; i >= 0; i--) {

            const animation = this._animations[i];

            if (!animation.target || animation.target.destroyed) {

                this._animations.splice(i, 1);

                continue;

            }

            switch (animation.type) {

                case "pulse":

                    this.updatePulse(animation);

                    break;

                case "bitmapSwap":

                    this.updateBitmapSwap(animation);

                    break;

            }

        }

    },

    //--------------------------------
    // Pulse
    //--------------------------------

    pulse(target, options = {}) {

        if (!target) {

            return;

        }

        const existing = this._animations.find(

            animation =>

                animation.target === target &&
                animation.type === "pulse"

        );

        if (existing) {

            return;

        }

        target.alpha = options.max ?? 1.0;

        this._animations.push({

            type: "pulse",

            target: target,

            min: options.min ?? 0.35,

            max: options.max ?? 1.0,

            speed: options.speed ?? 0.02,

            direction: -1

        });

    },

    //--------------------------------
    // Bitmap Swap
    //--------------------------------

    bitmapSwap(target, folder, frames, options = {}) {

        if (!target) {

            return;

        }

        if (!frames || frames.length < 2) {

            return;

        }

        const existing = this._animations.find(

            animation =>

                animation.target === target &&
                animation.type === "bitmapSwap"

        );

        if (existing) {

            return;

        }

        target.bitmap = LOGICPULSE.Assets.load(

            folder,

            frames[0]

        );

        this._animations.push({

            type: "bitmapSwap",

            target: target,

            folder: folder,

            frames: frames,

            frameIndex: 0,

            timer: 0,

            interval: options.interval ?? 30

        });

    },

    //--------------------------------
    // Stop
    //--------------------------------

    stop(target) {

        this._animations = this._animations.filter(

            animation => animation.target !== target

        );

        if (!target) {

            return;

        }

        target.alpha = 1.0;

    },

    //--------------------------------
    // Clear
    //--------------------------------

    clear() {

        for (const animation of this._animations) {

            if (animation.target) {

                animation.target.alpha = 1.0;

            }

        }

        this._animations = [];

    },

    //--------------------------------
    // Pulse Update
    //--------------------------------

    updatePulse(animation) {

        animation.target.alpha +=

            animation.speed * animation.direction;

        if (animation.target.alpha <= animation.min) {

            animation.target.alpha = animation.min;

            animation.direction = 1;

        }

        else if (animation.target.alpha >= animation.max) {

            animation.target.alpha = animation.max;

            animation.direction = -1;

        }

    },

    //--------------------------------
    // Bitmap Swap Update
    //--------------------------------

    updateBitmapSwap(animation) {

        animation.timer++;

        if (animation.timer < animation.interval) {

            return;

        }

        animation.timer = 0;

        animation.frameIndex++;

        if (animation.frameIndex >= animation.frames.length) {

            animation.frameIndex = 0;

        }

        animation.target.bitmap = LOGICPULSE.Assets.load(

            animation.folder,

            animation.frames[animation.frameIndex]

        );

    },

};

//=============================================================================
// Scene Hook
//=============================================================================

(() => {

    const aliasUpdate = Scene_Base.prototype.update;

    Scene_Base.prototype.update = function() {

        aliasUpdate.call(this);

        LOGICPULSE.Animator.update();

    };

})();


